+    const connection: MockConnection = {
+      destroy: vi.fn(),
+      subscribe: vi.fn(),
+      on: vi.fn((event: string, handler: EventHandler) => {
+        handlers.set(event, handler);
+      }),
+      off: vi.fn(),
+      receiver: {
+        speaking: {
+          on: vi.fn(),
+          off: vi.fn(),
+        },
+        subscribe: vi.fn(() => ({
+          on: vi.fn(),
+          [Symbol.asyncIterator]: async function* () {},
+        })),
+      },
+      handlers,
+    };
+    return connection;
+  };
