+    const oldDestroyed = oldConnection.handlers.get("destroyed");
+    expect(oldDestroyed).toBeTypeOf("function");
+    oldDestroyed?.();
+
+    expect(manager.status()).toEqual([
+      {
+        ok: true,
+        message: "connected: guild g1 channel c2",
+        guildId: "g1",
+        channelId: "c2",
